#include<bits/stdc++.h>
#define LL long long
#define UInt unsigned int
#define ULL unsigned long long
#define LD long double
#define pii pair<int,int>
#define pLL pair<LL,LL>
#define pDD pair<LD,LD>
#define fr first
#define se second
#define pb push_back
#define isr insert
#define _i128 __int128
using namespace std;
const int N = 40005;
const int NB = 805;
int n,Q,a[N],Ls[N],cnt,B,tot;
int L[NB],R[NB],bel[N];
int sum[NB][N],zh[NB][NB],c[N],Ans;
int read(){
    int su=0,pp=1;char ch=getchar();
    while(ch<'0'||ch>'9'){if(ch=='-')pp=-1;ch=getchar();}
    while(ch>='0'&&ch<='9'){su=su*10+ch-'0';ch=getchar();}
    return su*pp;
}
int ask(int l,int r,int k){
    return sum[r][k]-sum[l-1][k];
}
void init_(){
    for(int i=1;i<=n;i++)Ls[i]=a[i];
    sort(Ls+1,Ls+n+1);
    cnt=unique(Ls+1,Ls+n+1)-Ls-1;
    for(int i=1;i<=n;i++)
        a[i]=lower_bound(Ls+1,Ls+cnt+1,a[i])-Ls;
    B=sqrt(n),tot=n/B;
    for(int i=1;i<=tot;i++)
        L[i]=R[i-1]+1,R[i]=R[i-1]+B;
    if(R[tot]<n)++tot,L[tot]=R[tot-1]+1,R[tot]=n;
    for(int i=1;i<=tot;i++){
        for(int x=1;x<=cnt;x++)
            sum[i][x]=sum[i-1][x];
        for(int x=L[i];x<=R[i];x++)
            sum[i][a[x]]++,bel[x]=i;
    }
    for(int i=1;i<=tot;i++){
        for(int x=1;x<=cnt;x++)c[x]=0;
        for(int j=i;j<=tot;j++){
            int res=zh[i][j-1];
            for(int x=L[j];x<=R[j];x++){
                c[a[x]]++;
                if(c[a[x]]>c[res])res=a[x];
                else if(c[a[x]]==c[res])res=min(res,a[x]);
            }
            zh[i][j]=res;
        }
    }
    for(int x=1;x<=cnt;x++)c[x]=0;
    return;
}
int query(int l,int r){
    int ll=bel[l],rr=bel[r];
    if(ll+1>=rr){//两个散块
        int res=0;
        for(int i=l;i<=r;i++){
            c[a[i]]++;
            if(c[a[i]]>c[res])res=a[i];
            else if(c[a[i]]==c[res])res=min(res,a[i]);
        }
        for(int i=l;i<=r;i++)c[a[i]]=0;
        return Ls[res];
    }else{//含有整块
        int res=zh[ll+1][rr-1];
        for(int i=l;i<=R[ll];i++){
            c[a[i]]++;
            int aa=ask(ll+1,rr-1,a[i])+c[a[i]];
            int ar=ask(ll+1,rr-1,res)+c[res];
            if(aa>ar)res=a[i];
            else if(aa==ar)res=min(res,a[i]);
        }
        for(int i=L[rr];i<=r;i++){
            c[a[i]]++;
            int aa=ask(ll+1,rr-1,a[i])+c[a[i]];
            int ar=ask(ll+1,rr-1,res)+c[res];
            if(aa>ar)res=a[i];
            else if(aa==ar)res=min(res,a[i]);
        }
        for(int i=l;i<=R[ll];i++)c[a[i]]=0;
        for(int i=L[rr];i<=r;i++)c[a[i]]=0;
        return Ls[res];
    }
}
int main(){
    n=read(),Q=read();
    for(int i=1;i<=n;i++)a[i]=read();
    init_();
    while(Q--){
        int l=(read()+Ans-1+n)%n+1;
        int r=(read()+Ans-1+n)%n+1;
        if(l>r)swap(l,r);
        Ans=query(l,r);cout<<Ans<<"\n";
    }
    return 0;
}
